// Stub QRCode client library (no-op). The server returns an SVG (pixSvg),
// so the client-side library is not required. This prevents loading errors.
(function (window) {
  window.QRCode = window.QRCode || {};
  window.QRCode.toCanvas = window.QRCode.toCanvas || function (el, text, opts) {
    // no-op: prefer server-provided SVG
    return null;
  };
})(window || this);
